// BTAlertDialog types — Figma node 2519-2209 (mobile M, 296px).

/// Visual variant of [BTAlertDialog].
///
/// Controls icon, confirm button colour, and default confirm label.
enum BTAlertDialogVariant {
  /// Shield-check icon. Confirm button: primary. Label: "Continue".
  success,

  /// Warning triangle icon. Confirm button: primary. Label: "Continue".
  warning,

  /// Help/question icon. Confirm button: primary. Label: "Continue".
  confirmation,

  /// Lightbulb icon. Confirm button: primary. Label: "Continue".
  info,

  /// Trash icon. Confirm button: destructive (error colour). Label: "Delete".
  delete,
}

// ignore_for_file: lines_longer_than_80_chars

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import 'package:btech_ui/src/components/molecules/alert_dialog/alert_dialog.types.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

/// BTAlertDialog — modal confirmation/information dialog.
/// Figma source: M node 2519-2209 (mobile 296px).
///
/// Mobile design: 296px wide, vertical button stack (Confirm on top, Cancel below).
/// Icon container 40×40px, icon 24px, padding 16px all sides.
///
/// ## Usage — inline (preview / showcase):
/// ```dart
/// BTAlertDialog(
///   variant: BTAlertDialogVariant.delete,
///   title: 'Delete this item?',
///   description: 'This action cannot be undone.',
///   onConfirm: () => doDelete(),
///   onCancel: () => Navigator.pop(context),
/// )
/// ```
///
/// ## Usage — as a proper centered overlay via [BTAlertDialog.show]:
/// ```dart
/// await BTAlertDialog.show(
///   context,
///   variant: BTAlertDialogVariant.delete,
///   title: 'Delete item?',
///   description: 'This cannot be undone.',
///   onConfirm: () { doDelete(); Navigator.pop(context); },
///   onCancel: () => Navigator.pop(context),
/// );
/// ```
class BTAlertDialog extends StatelessWidget {
  const BTAlertDialog({
    required this.variant,
    required this.title,
    required this.description,
    this.confirmLabel,
    this.cancelLabel = 'Cancel',
    this.has2ndButton = true,
    this.onConfirm,
    this.onCancel,
    this.child,
    super.key,
  });

  /// Visual variant — controls icon, confirm button colour, and default label.
  final BTAlertDialogVariant variant;

  /// Primary heading text.
  final String title;

  /// Supporting description text.
  final String description;

  /// Overrides the default confirm label ('Continue' or 'Delete').
  final String? confirmLabel;

  /// Label for the cancel button. Defaults to 'Cancel'.
  final String cancelLabel;

  /// Whether to show the cancel (2nd) button. Defaults to true.
  final bool has2ndButton;

  /// Called when the confirm button is tapped.
  final VoidCallback? onConfirm;

  /// Called when the cancel button is tapped.
  final VoidCallback? onCancel;

  /// Optional widget rendered between description and buttons.
  final Widget? child;

  // ── Icon asset paths ─────────────────────────────────────────────────────────

  static const _iconPaths = {
    BTAlertDialogVariant.success:
        'packages/btech_ui/assets/icons/alert_dialog/verified_user.svg',
    BTAlertDialogVariant.warning:
        'packages/btech_ui/assets/icons/alert_dialog/e911_emergency.svg',
    BTAlertDialogVariant.confirmation:
        'packages/btech_ui/assets/icons/alert_dialog/siren_question.svg',
    BTAlertDialogVariant.info:
        'packages/btech_ui/assets/icons/alert_dialog/lightbulb.svg',
    BTAlertDialogVariant.delete:
        'packages/btech_ui/assets/icons/alert_dialog/delete.svg',
  };

  // ── Helpers ──────────────────────────────────────────────────────────────────

  bool get _isDelete => variant == BTAlertDialogVariant.delete;

  String get _resolvedConfirmLabel =>
      confirmLabel ?? (_isDelete ? 'Delete' : 'Continue');

  BTButtonVariant get _confirmVariant =>
      _isDelete ? BTButtonVariant.destructive : BTButtonVariant.primary;

  // ── show() convenience ───────────────────────────────────────────────────────

  /// Shows this dialog centered on screen using [showDialog].
  ///
  /// ```dart
  /// await BTAlertDialog.show(
  ///   context,
  ///   variant: BTAlertDialogVariant.delete,
  ///   title: 'Delete item?',
  ///   description: 'This cannot be undone.',
  ///   onConfirm: () { doDelete(); Navigator.pop(context); },
  ///   onCancel: () => Navigator.pop(context),
  /// );
  /// ```
  static Future<void> show(
    BuildContext context, {
    required BTAlertDialogVariant variant,
    required String title,
    required String description,
    String? confirmLabel,
    String cancelLabel = 'Cancel',
    bool has2ndButton = true,
    VoidCallback? onConfirm,
    VoidCallback? onCancel,
    Widget? child,
  }) =>
      showDialog(
        context: context,
        barrierColor: const Color(0x80000000), // rgba(0,0,0,0.5)
        builder: (_) => Dialog(
          insetPadding:
              EdgeInsets.symmetric(horizontal: 40.0, vertical: 24.0),
          backgroundColor: Colors.transparent,
          child: BTAlertDialog(
            variant: variant,
            title: title,
            description: description,
            confirmLabel: confirmLabel,
            cancelLabel: cancelLabel,
            has2ndButton: has2ndButton,
            onConfirm: onConfirm,
            onCancel: onCancel,
            child: child,
          ),
        ),
      );

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;

    return Container(
      width: 296.0,
      padding: EdgeInsets.all(16.0),
      decoration: BoxDecoration(
        color: c.bg.primary,
        borderRadius: BorderRadius.circular(r.md),
        boxShadow: BTShadow.elevation.lg,
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // ── Content ─────────────────────────────────────────────────────────
          Column(
            children: [
              // Icon container 40×40
              Container(
                width: 40.0,
                height: 40.0,
                padding: EdgeInsets.all(8.0),
                decoration: BoxDecoration(
                  color: c.bg.subtle,
                  borderRadius: BorderRadius.circular(r.md),
                ),
                child: SvgPicture.asset(
                  _iconPaths[variant]!,
                  width: 24.0,
                  height: 24.0,
                  colorFilter: ColorFilter.mode(
                    c.text.secondary,
                    BlendMode.srcIn,
                  ),
                ),
              ),
              SizedBox(height: 16.0),

              // Title
              Text(
                title,
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 16.0,
                  fontWeight: FontWeight.w700,
                  height: 20 / 16,
                  color: c.text.primary,
                ),
              ),
              SizedBox(height: 4.0),

              // Description
              Text(
                description,
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 12.0,
                  fontWeight: FontWeight.w500,
                  height: 16 / 12,
                  color: c.text.secondary,
                ),
              ),

              // Optional slot
              if (child != null) ...[
                SizedBox(height: 12.0),
                child!,
              ],
            ],
          ),
          SizedBox(height: 24.0),

          // ── Buttons (vertical, full-width, Confirm on top) ───────────────────
          Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              SizedBox(
                width: double.infinity,
                child: BTButton(
                  label: _resolvedConfirmLabel,
                  variant: _confirmVariant,
                  onPressed: onConfirm,
                ),
              ),
              if (has2ndButton) ...[
                SizedBox(height: 8.0),
                SizedBox(
                  width: double.infinity,
                  child: BTButton(
                    label: cancelLabel,
                    variant: BTButtonVariant.secondaryLight,
                    onPressed: onCancel,
                  ),
                ),
              ],
            ],
          ),
        ],
      ),
    );
  }
}
